"""
MABE Bootstrap: De Novo Generator + 3D Pipeline — Complete

Run: python3 bootstrap_denovo_3d.py

Prereqs: pip install rdkit scipy --break-system-packages

Creates 8 files:
  core/de_novo_generator.py     — fragment-based enumeration + 3D scoring
  core/design_engine_v2.py      — unified discovery + rerank_3d()
  core/conformer_3d.py          — ETKDG → donor locator → Kabsch → strain
  core/ideal_pocket.py          — physics-optimal 3D pocket
  + 4 test files

New 3D pipeline:
  generate_and_score_3d("Cu2+", donor_subtypes=["N_amine"]*4)
  discover_binders("Cu2+", score_3d_flag=True, donor_subtypes_3d=[...])
  rerank_3d(candidates, "Cu2+", donor_subtypes=[...])

Tests: 77 de_novo + 21 design_engine + 29 conformer + 40 ideal_pocket = 167
"""
import base64, pathlib

FILES = {
    "core/de_novo_generator.py": "",
    "tests/test_de_novo_generator.py": "",
    "core/design_engine_v2.py": "",
    "tests/test_design_engine_v2.py": "",
    "core/conformer_3d.py": "",
    "tests/test_conformer_3d.py": "",
    "core/ideal_pocket.py": "",
    "tests/test_ideal_pocket.py": "",
}

def main():
    for path, b64 in FILES.items():
        p = pathlib.Path(path)
        p.parent.mkdir(parents=True, exist_ok=True)
        p.write_bytes(base64.b64decode(b64))
        print(f"  Wrote {path} ({len(base64.b64decode(b64)):,} bytes)")
    print()
    print("  python3 -m pytest tests/test_conformer_3d.py tests/test_ideal_pocket.py tests/test_design_engine_v2.py -v")

if __name__ == "__main__":
    main()